import React from 'react';
import styled from 'styled-components';
import { HashLink as Linkh } from 'react-router-hash-link';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Home from '../Home';
import Notfound from '../Notfound';
import conversor_interface from '../conversor_interface'; 

const Ul = styled.ul`
  margin: 0;
  text-align: center;
  display: flex;
  flex-flow: row nowrap;
  text-decoration-line: none;

  .navbar_lateral_esquerdo ul li p{
    text-decoration-line: none;
  }

  p{
    @media (max-width: 700px){
      color: white;
    }
    color: black;  
    line-height: 40px;
    font-size: 1.2em;
    display: inline-block;  
  }
  
  ul li{
    color: white;
    margin-left: 3%;
    list-style-type: none;
  }
    @media (min-width: 981px){
    .navbar_lateral_esquerdo{
      position: fixed;
      margin-top: 5%;
      margin-left: 2%;
      -webkit-text-decoration-line: none;
      text-decoration-line: none;
    }
  }

  @media (min-width: 1450px){
    margin-left: 10%;
  }
   
   @media (max-width: 980px) {
    background-color: darkslateblue;
    position: fixed;
    transform: ${({ open }) => open ? 'translateX(0)': 'translateX(100%)'};
    top: 0;
    right: 0;
    margin-right: 0px;  
    margin-top: 0px;
    height: 100vh;
    width: 200px;
    padding-top: 3.5rem;
    transition: transform 0.3 ease-in-out;
    
    p{
      line-height: 40px;
      font-size: 1.2em;
      display: inline-block;
    }

    .navbar_lateral_esquerdo{
      position: fixed;
      margin-top: 5%;
      margin-left: 20%;
      text-decoration-line: none;
    }

    .navbar_lateral_esquerdo ul li p{
      text-decoration-line: none;
    }
    li {
        margin-left: 20%;
        text-align: left;
        }
    }
`;

    const Rightnav = ({open}) => {
        return(
          <>
      <Router>
      <Ul open={open}>
        <div className="navbar_lateral_esquerdo">
        <img src="https://www.estevesrodrigo.com/img/eu.png" className="eu" alt="Minha-Foto" width="220" height="220"></img>
      <ul>
        <li><Linkh to="/#Home"><p>Home</p></Linkh></li>
        <li><Linkh to="/#About"><p>About</p></Linkh></li>
        <li><Linkh to="/#Education"><p>Education</p></Linkh></li>
        <li><Linkh to="/#Projects"><p>Projects</p></Linkh></li>
        <li><Linkh to="/#Technical_Skills"><p>Technical Skills</p></Linkh></li>
      </ul>
        </div>
      </Ul>

      <Switch>
        <Route path="/" exact component={Home}>
        </Route>
        <Route path="/#About" component={Home}>
        </Route>
        <Route path="/#Education" component={Home}>
        </Route>
        <Route path="/Projects" component={Home}>
        </Route>
        <Route path="/#Technical_Skills" component={Home}>
        </Route>
        <Route path="/conversor" component={conversor_interface}>
        </Route>
        <Route path="*" component={Notfound}>
        </Route>
      </Switch>
     
      </Router>
      </>
        )
    }

export default Rightnav;