import React from 'react';

export const Education = ({img, height, width}) => {
    return(
    <div className="education">
        <h2><a href id="Education">Education</a></h2>
            <div className="education_paraf">
                <img src={img} ClassName="logo-unopar"
                width={width} height={height} alt="logo"></img>
                    <div className="descrição">
                        <h3>Universidade Norte do Paraná</h3>
                        <p>Technologist - Systems Analysis and Development</p>
                        <p>Fev 2020 - 2022</p>
                    </div>
            </div>
    </div>
    );
}