import React from 'react';

export const TechnologySkills = ({frameworks}) => {
    return(
        <div className="technology_skills" id="Technical_Skills">
        <h2>Technology Skills</h2>
        <h4>Programming Languages</h4>
        <li>Javascript, Java, Python, C and Typescript</li>
        <h4>Frameworks</h4>
        <li>{frameworks}</li>
        <h4>Others</h4>
        <li>Node.js, SQL, CSS, HTML5, Git, Redux, React-hooks, Styled-components, Npm,
              Cpanel, Ubuntu, Json, Maven, SASS and Others</li>
    </div>
    );
}